// Script Continued Below
// 2.7 
// STRY0102134 - Apply Default Schedule to Task Information
// 2.7.0 | 2021-11-08 | mmcc | DFCT0010645 - Platform Reopen Task button does not open modal for some Views
// 2.7.3 | 2022-04-20 | raj  | DFCT0010874 - "Information Only"  Task is NOT working on the "Simple Task" form. The state doesn't move to "Complete".
// 2.8 | 2022-06-08 | raj    | STRY0122767 - Draft Task- Update "Publish Task(s)" buttons locations; Update Messaging for "Where to Publish Task(s)"
// 2.8 | 2022-06-27 | raj | STRY0123191 - Warning Modal- Rejecting an Approval Subtask will close all "Approval Dependent Tasks" 
// 2.8 | 2022-08-10 | raj | DFCT0011152 - Reviewer comments does NOT display when user "Approve and Sign" or "Concur and sign" a Task & Template task 
// 2.8    | 2022-08-16 - raj -  DFCT0011108 - Tasker Schedule: "# of Days added to today to set the Suspense Date for Acknowledgment Tasker Type" does NOT follow system schedule on the  QUICK TASKING
// 2.8    | 2022-09-14 - raj -  DFCT0011217 - Stretch - "My Attachments' should be ONLY allowed to the associated  Task to the Task owner when uploading files in the My Attachment tab
// 2.8.0 | 2022-09-21| raj  |  STRY0130088 - 2.8 Certifier requested updates - 6. isLoading in OnChange ClientScript
// 2.8.1 | 2022-10-17 |raj |  STRY0127550 - Tech Debt - Task Types are used in code with hard coded values, modify to use a new value field in the table
// 2.8.1 | 2022-09-21| raj  |  STRY0130635 - Task Form- Assignee is Out of Office
(function executeRule(current, previous /*null when async*/) {
	// DFCT0011108 - moved to top as used more than once
	var tdc = new TaskerDurationCalculator();
	// 2.7.0 | 2021-11-08 | mmcc | DFCT0010645 - Platform Reopen Task button does not open modal for some Views
	g_scratchpad.active = current.active; // will be true/false as string 

	// DFCT0010874
	g_scratchpad.assigned_to = current.getValue("assigned_to");

	// STRY0085438
	var taskerHelpers = new TaskerHelpers();
	var taskPermissions = taskerHelpers.updateTaskPermission(current);
	g_scratchpad.taskPermissions = JSON.stringify(taskPermissions);

	// STRY0130635
	g_scratchpad.originalSuspenseDate = current.getDisplayValue("suspense_date");
	var oooTaskToCheck=current.getUniqueValue();
	// if new record and parent is set, then the new record starts with parent config
	if(current.isNewRecord() && current.parent){
		oooTaskToCheck = current.getValue("parent");
	}
	g_scratchpad.taskScheduledooo = new Out_of_Office().getActiveTaskOOOSchedules(oooTaskToCheck);
	var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('DTech_Out_of_Office');
	g_scratchpad.messages = taskWidgetIconsAndMessage.loadMessages();
	g_scratchpad.styleSheetLinks = taskWidgetIconsAndMessage.loadStyleSheetLinkss();

	var taskOwnerId = current.u_task_requester;
	// DFCT0011152 - added to scratchpad
	g_scratchpad.taskOwner = taskOwnerId;
	var OrgScripts = new ClientOrganizationalScripts();
	g_scratchpad.isUserOUTAOfAnotherUserBasedOnDefaultOu = OrgScripts.isUserOUTAOfAnotherUserBasedOnDefaultOu(gs.getUserID(), taskOwnerId);
	var primary_assignee = current.primary_assignee;
	var reviewer = current.u_reviewer;
	// DFCT0011152 - added to scratchpad
	g_scratchpad.reviewer = reviewer;
	var UserPermissions = new UserInfoScripts();	
	g_scratchpad.reviewerInOUTA_OU = UserPermissions.IsUserInOU(primary_assignee, reviewer);
	g_scratchpad.isTAExternal = current.tasking_authority !='' ? current.tasking_authority.u_external_flag : false;
	g_scratchpad.isTaskManagerOUTA = UserPermissions.IsUserOUTA(gs.getUserID(),primary_assignee);
	g_scratchpad.currentState = (current.isNewRecord()) ? "New" : current.getValue("state");

	// STRY0127550 load client constent for type display values
	var taskerTypes =  new TaskerTypes();
	g_scratchpad.taskerTypesDisplayValues = taskerTypes.getDisplayValues();
	g_scratchpad.taskerTypesConstants = taskerTypes.getValueConstants();

	// this is tasker_type value
	g_scratchpad.taskType = current.getDisplayValue("tasker_type.u_value");
	// STRY0123191 - pass taskerNumber in cases where it isn't on the form
	g_scratchpad.taskerNumber = current.getDisplayValue("taskernumber");

	// STRY0130088
	g_scratchpad.category = current.getValue('category') +'';
	g_scratchpad.subCategoryCount = 0;
	if(g_scratchpad.category != ""){
		g_scratchpad.subCategoryCount = taskerHelpers.getSubCategoryCount(g_scratchpad.category);
	}
	var defaultFromView = new tasker_User_Form_Preferences().getDefaultFormViewForTaskType(g_scratchpad.taskType, g_scratchpad.taskType);
	g_scratchpad.u_servicenow_form_view = defaultFromView.sys_id;


	g_scratchpad.maxTaskOrder = 0;
	g_scratchpad.taskParent = current.parent;
	g_scratchpad.calchaschildren = current.calchaschildren;
	// STRY0091379 - is user in the OU of the Primary Assignee
	g_scratchpad.isUserInPrimaryAssigneeOU = UserPermissions.IsUserInOU(primary_assignee, gs.getUserID());

	// STRY0071489
	g_scratchpad.primary_office_must_match_Internal_tasking_authority = 
		gs.getProperty('x_153465_discovert.primary_office_must_match_Internal_tasking_authority');

	// STRY0071533 - get system setting on load
	g_scratchpad.suspenseDatesAndExpctedStartDatesMustBeInTheFuture = gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future');

	// DFCT0011108
	g_scratchpad.acknowledgementSuspenseDate = tdc.addDaysAcknowledgementSuspenseDate(current.sys_id, current.primary_office);

	g_scratchpad.parent_sys_id = '';
	g_scratchpad.parent_active = '';
	g_scratchpad.parent_number = '';

	// set the maximum value to display in the routes dropdown
	var gaGetMaxTaskOrder;
	if (!current.parent.nil()){
		g_scratchpad.parent_sys_id = current.parent + '';
		g_scratchpad.parent_active = current.parent.active;
		g_scratchpad.parent_number = current.parent.number;
//gs.addInfoMessage('Calculating Max routes for task with Parent: ' + current.parent.short_description);
		gaGetMaxTaskOrder = new GlideAggregate('x_153465_discovert_route_task_instance');
		gaGetMaxTaskOrder.addQuery('parent', current.parent);
		gaGetMaxTaskOrder.addAggregate('MAX', 'task_order');
		gaGetMaxTaskOrder.groupBy('parent');
		gaGetMaxTaskOrder.query();
		if(gaGetMaxTaskOrder.next()){
			g_scratchpad.maxTaskOrder = gaGetMaxTaskOrder.getAggregate('MAX', 'task_order');
//gs.addInfoMessage('scratchpad set to max routes g_scratchpad.maxTaskOrder: ' + g_scratchpad.maxTaskOrder);
		}
	}
	// STRY0076615 - Task Form – TASK ORDER Field – Set order value on load
	if(current.isNewRecord()){
		// if top task, or no siblings found, set the value to 1
		if (current.parent == '' || g_scratchpad.maxTaskOrder == 0){
			g_scratchpad.currentTaskOrderValue = 1;
		} else {
			// if not first task set the current order to be the highest order currently in the tree so the tasks build in the current order.
			g_scratchpad.currentTaskOrderValue = g_scratchpad.maxTaskOrder;
		}

		// STRY0110317 - only override if not already set based on parent or template creation
		if(current.suspense_date.nil()){
			// STRY0127550 get value instead of a display string and compare to a constant instead of a hard coded value
			if(current.getDisplayValue("tasker_type.u_value") == TaskerTypes.CONST_TASKER_TYPE_ACKNOWLEDGEMENT){
				current.setValue("suspense_date", g_scratchpad.acknowledgementSuspenseDate);
			} else {
				// STRY0099280
				current.suspense_date = new tasking_System_Settings_Scripts().getDefaultTime(current);				
			}
		}

		// DFCT0010482 - Any Tasker User can create a subtask on ANY task in the system
		// the method call will put an error on the screen stating the user cannot create the task
		g_scratchpad.canCreateTask =  new uiConditionCheck().createTaskAction(current);
		// DFCT0011217
		g_scratchpad.canAttach = true;
	} else {
		// save current value to set back in form after reloading option list
		g_scratchpad.currentTaskOrderValue = current.task_order;
		// DFCT0011217
		var TaskACLs = new TaskerTaskACLs(current);
		g_scratchpad.canAttach = TaskACLs.canAttach() == true;

	}

	// move to task, not just on parent
	// STRY0016025- RAJ 2019-04-20 - Determine if Tasker close date is beyond the allowable reopen days
	g_scratchpad.closed_to_long_to_reopen = false;
	g_scratchpad.ReopenMaxDays = gs.getProperty('x_153465_discovert.ReopenMaxDays');

	g_scratchpad.closed_at = current.closed_at;
	var closedAt = new GlideDateTime(current.closed_at);
	// STRY0102134 - Apply Default Schedule to Task Information
	var maxReopenDate;
	if(!current.active){
		var today = new GlideDateTime().getNumericValue();
		// find the end date in the schedule
		maxReopenDate = tdc.calculateDateOfAddedBusinessDays(null, g_scratchpad.ReopenMaxDays, closedAt);
		g_scratchpad.closed_to_long_to_reopen = (today > new GlideDateTime(maxReopenDate).getNumericValue());
	}

	var bCanReopen = (!current.active && (current.parent?current.parent.active:true));
	g_scratchpad.hasCanceledSubtask = 'false';
	// STRY0016025- RAJ 2019-04-20 - all logic passed, reopen the Task.
	if (bCanReopen){
		var grSubTasksClosedIncomplete = new GlideRecord('x_153465_discovert_route_task_instance');
		grSubTasksClosedIncomplete.addQuery('parent', current.getUniqueValue());
		grSubTasksClosedIncomplete.addQuery('state', 4);
		grSubTasksClosedIncomplete.query();
		while (grSubTasksClosedIncomplete.next()){
			// recursively reopen down the tree
			g_scratchpad.hasCanceledSubtask = 'true';
			break;
		}
	}
	// STRY0109183 - Remove "Tasker Email" related list/ tab when "Disable Email Task Information" is set to true
	g_scratchpad.emailDiabled = gs.getProperty("x_153465_discovert.#DisableExportTaskToEmailFunction") == "true";
	g_scratchpad.taskToPublishMessage = "";
	// STRY0122767 - if draft check if user can publish and raise message for where publish can happen
	if(current.state == -6){
		var taskToPublish = taskerHelpers.getTaskToPublish(current);

		if(taskToPublish && taskToPublish != ''){
			var page_id = gs.action.getGlideURI().get("id");
			var gURL = gs.getProperty("glide.servlet.uri");

			if(page_id && page_id != null && page_id != ''){
				var portal_suffix = new tasker_User_Form_Preferences()._getDefaultServicePortalSuffix();
				gURL = gURL +
					portal_suffix +
					"?id="+ gs.action.getGlideURI().get("id") +
					"&table=" + current.getTableName() + 
					"&sys_id=" + taskToPublish;
			} else {
				gURL = gURL + current.getTableName() + ".do?" + 
					"&sys_id=" + taskToPublish;
			}

			g_scratchpad.taskToPublishMessage = 
				gs.getMessage("Tasker - Active Tasks cannot exist under Draft Tasks. Navigate to the Earliest Task-Order Draft Task to publish this Draft Task.") + 
				"<a href=" +  gURL.toString() + "&target=_blank" + ">" +
				gs.getMessage("Tasker - Take me to the Earliest Task-Order Draft Task...") + "</a>";
		}
	}
})(current, previous);
